What does this program print when the input is `5`?

```cpp
#include <iostream>
int main()
{
    int n {};
    std::cin >> n;
    if (n > 0)
        std::cout << "positive\n";
        std::cout << "done\n";
    return 0;
}
```

What does this program print when the input is `0`?

```cpp
#include <iostream>
int main()
{
    int x {};
    std::cin >> x;
    if (x > 0)
        std::cout << "positive\n";
    else if (x < 0)
        std::cout << "negative\n";
    else
        std::cout << "zero\n";
    return 0;
}
```

